UPDATE core_vocabulary SET word = 'well', meaning_zh = '好地；顺利地；健康地', definition_en = 'in a good, successful, or satisfactory way', primary_part_of_speech = 'adverb', phonetic_us = '/wɛl/', phonetic_uk = '/wel/', updated_at = CURRENT_TIMESTAMP WHERE id = 'well';
